from numeric_ops import Calculator

class DoublingCalculator(Calculator):
    @override
    def compute(self) -> float:
        base: float = super().compute()
        return base * 2.0

class SquaringCalculator(Calculator):
    @override
    def compute(self) -> float:
        base: float = super().compute()
        return base * base
